import unicodedata, re

def normalize(s: str) -> str:
    s = unicodedata.normalize("NFC", s)     # canonical Unicode form
    s = s.strip()                            # remove surrounding whitespace
    s = re.sub(r'[.!?,;]+$', '', s)         # strip trailing punctuation
    return s.lower()

def robust_exact(output: str, expected: str) -> float:
    return 1.0 if normalize(output) == normalize(expected) else 0.0

import json, jsonschema

RESPONSE_SCHEMA = {
    "type": "object",
    "required": ["category", "confidence"],
    "properties": {
        "category": {"type": "string", "enum": ["billing", "shipping", "technical", "other"]},
        "confidence": {"type": "number", "minimum": 0, "maximum": 1},
        "explanation": {"type": "string"},
    },
    "additionalProperties": False,
}

def json_schema_grader(output: str, schema: dict) -> float:
    try:
        data = json.loads(output)
        jsonschema.validate(data, schema)
        return 1.0
    except (json.JSONDecodeError, jsonschema.ValidationError):
        return 0.0

# Partial credit: award points for valid JSON even if schema fails
def json_schema_grader_partial(output: str, schema: dict) -> float:
    try:
        data = json.loads(output)
    except json.JSONDecodeError:
        return 0.0   # not even valid JSON
    try:
        jsonschema.validate(data, schema)
        return 1.0   # full marks
    except jsonschema.ValidationError:
        return 0.5   # valid JSON, wrong shape

import anthropic, json

client = anthropic.Anthropic()

JUDGE_PROMPT_TEMPLATE = """You are an expert evaluator. Score the model response below.

Task given to the model:
{task}

Model response:
{response}

Reference answer (if available):
{reference}

Rubric:
{rubric}

Respond with JSON only: {{"score": <1-5>, "reason": "<one sentence>"}}
Do not add any text outside the JSON object."""

def llm_judge(
    task: str,
    response: str,
    rubric: str,
    reference: str = "N/A",
    judge_model: str = "claude-haiku-4-5-20251001",
) -> dict:
    prompt = JUDGE_PROMPT_TEMPLATE.format(
        task=task, response=response, rubric=rubric, reference=reference
    )
    result = client.messages.create(
        model=judge_model,
        max_tokens=256,
        messages=[{"role": "user", "content": prompt}],
    )
    try:
        return json.loads(result.content[0].text)
    except json.JSONDecodeError:
        return {"score": None, "reason": "Judge returned non-JSON output"}

from dataclasses import dataclass

@dataclass
class GradeResult:
    score: float          # 0.0 to 1.0 aggregate
    subscores: dict       # individual grader results
    passed: bool          # whether the case passed the gate

def multi_grader(output: str, case: dict) -> GradeResult:
    scores = {}

    # Dimension 1: correct format
    scores['format'] = json_schema_grader(output, case.get('schema', {}))

    # Dimension 2: contains required acknowledgment
    scores['acknowledgment'] = contains_grader(output, case.get('required_phrase', ''))

    # Dimension 3: overall quality (LLM judge)
    judge_result = llm_judge(case['input'], output, case['rubric'])
    scores['quality'] = (judge_result.get('score') or 0) / 5.0  # normalize to 0-1

    # Weighted aggregate
    weights = {'format': 0.3, 'acknowledgment': 0.2, 'quality': 0.5}
    aggregate = sum(scores[k] * weights[k] for k in scores)

    # Hard gate: format must pass, or overall score is 0
    if scores['format'] < 1.0:
        aggregate = 0.0

    return GradeResult(score=round(aggregate, 3), subscores=scores, passed=aggregate >= 0.7)
